529	void RTLIL::Cell::unsetPort(RTLIL::IdString portname)
530	{
531		RTLIL::SigSpec signal;
532		auto conn_it = connections_.find(portname);
533	
534		if (conn_it != connections_.end())
535		{
536			for (auto mon : module->monitors)
537				mon->notify_connect(this, conn_it->first, conn_it->second, signal);
538	
539			if (module->design)
540				for (auto mon : module->design->monitors)
541					mon->notify_connect(this, conn_it->first, conn_it->second, signal);
542	
543			if (yosys_xtrace) {
544				log("#X# Unconnect %s.%s.%s\n", this->module, this, portname.unescape());
545				log_backtrace("-X- ", yosys_xtrace-1);
546			}
547	
548			if (module->design && module->design->flagBufferedNormalized) {
549				if (conn_it->second.is_wire()) {
550					Wire *w = conn_it->second.as_wire();
551					if (w->driverCell_ == this && w->driverPort_ == portname) {
552						w->driverCell_ = nullptr;
553						w->driverPort_ = IdString();
554						module->buf_norm_wire_queue.insert(w);
555					} else if (w->driverCell_) {
556						log_assert(w->driverCell_->getPort(w->driverPort_) == w);
557					}
558				}
559	
560				if (type == ID($connect)) {
561					for (auto &[port, sig] : connections_) {
562						for (auto &chunk : sig.chunks()) {
563							if (!chunk.wire)
564								continue;
565							auto it = module->buf_norm_connect_index.find(chunk.wire);
566							if (it == module->buf_norm_connect_index.end())
567								continue;
568							it->second.erase(this);
569							if (it->second.empty())
570								module->buf_norm_connect_index.erase(it);
571						}
572					}
573					connections_.erase(conn_it);
574					for (auto &[port, sig] : connections_) {
575						for (auto &chunk : sig.chunks()) {
576							if (!chunk.wire)
577								continue;
578							module->buf_norm_connect_index[chunk.wire].insert(this);
579						}
580					}
581					return;
582				}
583			}
584	
585			connections_.erase(conn_it);
586		}
587	}
588	
589	void RTLIL::Cell::setPort(RTLIL::IdString portname, RTLIL::SigSpec signal)
590	{
591		auto r = connections_.insert(portname);
592		auto conn_it = r.first;
593		if (!r.second && conn_it->second == signal)
594			return;
595	
596		for (auto mon : module->monitors)
597			mon->notify_connect(this, conn_it->first, conn_it->second, signal);
